      const typeKey = `${String(item.extension || "").trim().toLowerCase()}:${String(item.content_type || "").trim().toLowerCase()}`;
      const byteSize = Number(item.byte_size);
      return Boolean(name) && name.length <= 120 && SUPPORT_ATTACHMENT_TYPES.has(typeKey)
