    // native helper below captures one of these session epochs, so an older
    // account response is discarded even while `/auth/me` is still loading.
    ++canonicalSessionEpoch;
    ++canonicalHydrationEpoch;
    ++canonicalAdminDataHydrationEpoch;
    ++adminErpNavigationEpoch;
    ++adminAuditSessionEpoch;
    ++memorySessionEpoch;
    ++operationHistorySessionEpoch;
    ++assetVaultSessionEpoch;
    ++assetVaultLifecycleHydrationEpoch;
    ++campaignSessionEpoch;
    ++campaignCalendarHydrationEpoch;
    ++projectCenterSessionEpoch;
    ++promptLibrarySessionEpoch;
    ++freePromptGallerySessionEpoch;
    ++projectPackageSessionEpoch;
    ++documentWorkspaceSessionEpoch;
    ++chatWorkspaceSessionEpoch;
    ++chatExecutionHydrationEpoch;
    ++analyticsWorkspaceSessionEpoch;
    ++channelStrategySessionEpoch;
    ++subtitleStudioSessionEpoch;
    ++workboardSessionEpoch;
    ++supportSessionEpoch;
    ++contentHandoffSessionEpoch;
    ++partnerCrmSessionEpoch;
    ++contentStudioSessionEpoch;
    ++mediaWorkspaceSessionEpoch;
    ++voiceStudioSessionEpoch;
    ++videoStudioSessionEpoch;
    ++imageStudioSessionEpoch;
    ++operationsSessionEpoch;
    ++operationsDeskSessionEpoch;
    ++operationsDeskHydrationEpoch;
    ++notificationSessionEpoch;
    ++accountActivitySessionEpoch;
    ++accountSecuritySessionEpoch;
