  async function hydrateProjectDetail(path) {
    const projectId = projectIdFromPath(path);
    if (!projectId) return;
    const requestEpoch = ++projectCenterDetailHydrationEpoch;
    // A newer Project detail load deliberately invalidates any document body
    // that was still being read for the prior detail selection.
    ++studioDocumentDetailHydrationEpoch;
    const sessionEpoch = projectCenterSessionEpoch;
    try {
      const result = await api(`/projects/${encodeURIComponent(projectId)}`);
      if (!projectCenterRequestIsCurrent(requestEpoch, projectCenterDetailHydrationEpoch, sessionEpoch, path)) return null;
      const project = result.data && result.data.project && typeof result.data.project === "object" ? result.data.project : null;
      const documents = result.data && Array.isArray(result.data.documents)
        ? result.data.documents.filter((item) => item && validProjectId(item.id)).slice(0, 100)
        : [];
      if (!project || String(project.id || "") !== projectId || !validProjectId(project.id)) throw new Error("project detail unavailable");
      if (!projectCenterRequestIsCurrent(requestEpoch, projectCenterDetailHydrationEpoch, sessionEpoch, path)) return null;
      merge({
        projectDetail: project,
        projectDocuments: documents,
        studioDocumentDetail: {},
        pageStates: { ...(base().pageStates || {}), [path]: "ready" }
      });
      return project;
    } catch (_) {
      if (!projectCenterRequestIsCurrent(requestEpoch, projectCenterDetailHydrationEpoch, sessionEpoch, path)) return null;
      merge({ projectDetail: {}, projectDocuments: [], studioDocumentDetail: {}, pageStates: { ...(base().pageStates || {}), [path]: "guarded" } });
      return null;
    }
  }

  async function hydrateProjectPackages(projectId, offsetValue) {
    const selectedProjectId = String(projectId || "").trim();
    if (selectedProjectId && !validProjectId(selectedProjectId)) return [];
    const scopeKey = selectedProjectId || "all";
    const expectedPath = selectedProjectId ? `/projects/${selectedProjectId}` : "/project-packages";
    const offset = projectPackageOffsetForScope(selectedProjectId, offsetValue);
    const requestEpoch = (projectPackageHydrationEpochs.get(scopeKey) || 0) + 1;
    projectPackageHydrationEpochs.set(scopeKey, requestEpoch);
    const sessionEpoch = projectPackageSessionEpoch;
    try {
      const result = await api(projectPackageListPath(selectedProjectId, offset));
      if (!projectPackageRequestIsCurrent(scopeKey, requestEpoch, sessionEpoch, expectedPath)) return null;
      const data = result.data && typeof result.data === "object" ? result.data : {};
      if (selectedProjectId && String(data.project_id || "") !== selectedProjectId) {
        throw new Error("Project Package history scope mismatch");
      }
      const items = Array.isArray(data.items)
        ? data.items
          .filter((item) => item && validProjectPackageId(item.id) && validProjectId(item.project_id) && (!selectedProjectId || String(item.project_id || "") === selectedProjectId))
          .slice(0, PROJECT_PACKAGE_LIST_LIMIT)
        : [];
      const listing = projectPackageListingProjection(selectedProjectId, offset, data, items.length);
      if (selectedProjectId) {
        const currentItems = base().projectPackageProjectItems && typeof base().projectPackageProjectItems === "object"
          ? base().projectPackageProjectItems
          : {};
        const currentListings = base().projectPackageProjectListings && typeof base().projectPackageProjectListings === "object"
          ? base().projectPackageProjectListings
          : {};
        merge({
          projectPackageProjectItems: projectPackageScopeMapWith(currentItems, selectedProjectId, items),
          projectPackageProjectListings: projectPackageScopeMapWith(currentListings, selectedProjectId, listing),
          pageStates: { ...(base().pageStates || {}), [expectedPath]: "ready" }
        });
      } else {
        merge({
          projectPackages: items,
          projectPackageListing: listing,
          pageStates: { ...(base().pageStates || {}), [expectedPath]: "ready" }
        });
      }
      return items;
    } catch (_) {
      if (!projectPackageRequestIsCurrent(scopeKey, requestEpoch, sessionEpoch, expectedPath)) return null;
      // Clear only the failing signed scope. The browser never substitutes a
      // Bot asset, an artifact from another Project, or an earlier page.
      if (selectedProjectId) {
        const currentItems = base().projectPackageProjectItems && typeof base().projectPackageProjectItems === "object"
          ? base().projectPackageProjectItems
          : {};
        const currentListings = base().projectPackageProjectListings && typeof base().projectPackageProjectListings === "object"
          ? base().projectPackageProjectListings
          : {};
        merge({
          projectPackageProjectItems: projectPackageScopeMapWith(currentItems, selectedProjectId, []),
          projectPackageProjectListings: projectPackageScopeMapWith(currentListings, selectedProjectId, projectPackageListingProjection(selectedProjectId, offset, {}, 0)),
          pageStates: { ...(base().pageStates || {}), [expectedPath]: "guarded" }
        });
      } else {
        merge({
          projectPackages: [],
          projectPackageListing: projectPackageListingProjection("", offset, {}, 0),
          pageStates: { ...(base().pageStates || {}), [expectedPath]: "guarded" }
        });
      }
      return [];
    }
  }

  async function hydrateStudioDocument(documentId) {
    if (!validProjectId(documentId)) throw new Error("Mã Studio Document không hợp lệ.");
    const requestEpoch = ++studioDocumentDetailHydrationEpoch;
    const sessionEpoch = projectCenterSessionEpoch;
    const expectedPath = currentPortalPath();
    try {
      const result = await api(`/projects/documents/${encodeURIComponent(documentId)}`);
      if (!projectCenterRequestIsCurrent(requestEpoch, studioDocumentDetailHydrationEpoch, sessionEpoch, expectedPath)) return null;
      const document = result.data && result.data.document && typeof result.data.document === "object" ? result.data.document : null;
      const expectedProjectId = projectIdFromPath(expectedPath);
      if (!document || String(document.id || "") !== String(documentId) || !validProjectId(document.id)
        || (expectedProjectId && String(document.project_id || "") !== expectedProjectId)) throw new Error("Studio Document không còn khả dụng.");
      const versions = result.data && Array.isArray(result.data.versions) ? result.data.versions.slice(0, 50) : [];
      if (!projectCenterRequestIsCurrent(requestEpoch, studioDocumentDetailHydrationEpoch, sessionEpoch, expectedPath)) return null;
      merge({ studioDocumentDetail: { document, versions } });
      return { document, versions };
    } catch (error) {
      if (!projectCenterRequestIsCurrent(requestEpoch, studioDocumentDetailHydrationEpoch, sessionEpoch, expectedPath)) return null;
      // A current failed document read must clear the previous private body;
      // a newer selection remains intact because its epoch is different.
      merge({ studioDocumentDetail: {} });
      throw error;
    }
  }

  function accountActivityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath) {
    return requestEpoch === accountActivityHydrationEpoch
      && sessionEpoch === accountActivitySessionEpoch
      && currentPortalPath() === expectedPath
      && expectedPath === "/account/activity"
      && Boolean(base().session && base().session.authenticated === true);
  }

  const ACCOUNT_SECURITY_OAUTH_PROVIDERS = new Set(["telegram", "google", "github", "apple"]);
  // Contact assurance is intentionally narrower than sign-in factors:
  // Telegram proves a canonical identity, not an email mailbox, and the
  // browser never receives any provider-returned contact address here.
  const ACCOUNT_SECURITY_CONTACT_PROVIDERS = new Set(["google", "github", "apple"]);
  const ACCOUNT_SECURITY_CONTACT_STATES = new Set([
    "verified_oauth", "verified_email_link", "unverified", "not_applicable", "unavailable"
  ]);
  const ACCOUNT_SECURITY_MFA_CODE_PATTERN = /^(?:[0-9]{6}|[A-HJ-NP-Z2-9]{4}-[A-HJ-NP-Z2-9]{4})$/;
  const ACCOUNT_SECURITY_MFA_TOKEN_PATTERN = /^[A-Za-z0-9_-]{32,160}$/;

  function validAccountSecurityMfaId(value) {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || "").trim());
  }

  function accountSecurityMfaCode(value) {
    const normalized = String(value || "").trim().toUpperCase().replace(/\s+/g, "");
    return ACCOUNT_SECURITY_MFA_CODE_PATTERN.test(normalized) ? normalized : "";
  }

  function accountSecurityMfaProjection(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const recoveryCodesRemaining = Number(source.recovery_codes_remaining);
    return {
      enabled: source.enabled === true,
      pending_enrollment: source.pending_enrollment === true && source.enabled !== true,
      runtime_available: source.runtime_available === true,
      password_factor_available: source.password_factor_available === true,
      recovery_codes_remaining: Number.isInteger(recoveryCodesRemaining)
        && recoveryCodesRemaining >= 0 && recoveryCodesRemaining <= 8
        ? recoveryCodesRemaining
        : 0
    };
  }

  function accountSecurityMfaEnrollmentProjection(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const factorId = String(source.factor_id || "").trim().toLowerCase();
    const enrollmentToken = String(source.enrollment_token || "").trim();
    const manualKey = String(source.manual_key || "").trim().toUpperCase();
    const digits = Number(source.digits);
    const periodSeconds = Number(source.period_seconds);
    const expiresInMinutes = Number(source.expires_in_minutes);
    if (!validAccountSecurityMfaId(factorId)
      || !ACCOUNT_SECURITY_MFA_TOKEN_PATTERN.test(enrollmentToken)
      || !/^[A-Z2-7]{16,128}$/.test(manualKey)
      || source.issuer !== "TOAN AAS"
      || source.algorithm !== "SHA1"
      || digits !== 6
      || periodSeconds !== 30
      || !Number.isInteger(expiresInMinutes)
      || expiresInMinutes < 1
      || expiresInMinutes > 30) return null;
    // Every value here is held only in the tab's in-memory store. The raw
    // setup key and opaque enrollment token are never persisted or rendered
    // outside the explicit setup card.
    return {
      factor_id: factorId,
      enrollment_token: enrollmentToken,
      manual_key: manualKey,
      issuer: "TOAN AAS",
      algorithm: "SHA1",
      digits: 6,
      period_seconds: 30,
      expires_in_minutes: expiresInMinutes
    };
  }

  function accountSecurityMfaLoginChallengeProjection(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const challengeId = String(source.challenge_id || "").trim().toLowerCase();
    const challengeToken = String(source.challenge_token || "").trim();
    const expiresInMinutes = Number(source.expires_in_minutes);
    if (source.mfa_required !== true
      || !validAccountSecurityMfaId(challengeId)
      || !ACCOUNT_SECURITY_MFA_TOKEN_PATTERN.test(challengeToken)
      || source.method !== "totp_or_recovery_code"
      || !Number.isInteger(expiresInMinutes)
      || expiresInMinutes < 1
      || expiresInMinutes > 10) return null;
    // The opaque challenge is browser-bound and transient. It never goes into
    // URL parameters, form drafts, localStorage or sessionStorage.
    return {
      challenge_id: challengeId,
      challenge_token: challengeToken,
      expires_in_minutes: expiresInMinutes
    };
  }

  function accountSecuritySafeTimestamp(value) {
    const text = typeof value === "string" ? value.trim() : "";
    return text && text.length <= 80 && !/[\u0000-\u001f\u007f]/.test(text) ? text : "";
  }

  function accountSecuritySessionProjection(value) {
    if (!value || typeof value !== "object") return null;
    const sessionRef = String(value.session_ref || "").trim().toLowerCase();
    // This is an opaque HMAC action handle rather than a database ID. It is
    // retained only in in-memory state long enough to populate a hidden
    // revoke form, and is never rendered as visible text or persisted.
    if (!/^[a-f0-9]{64}$/.test(sessionRef)) return null;
    return {
      session_ref: sessionRef,
      current: value.current === true,
      created_at: accountSecuritySafeTimestamp(value.created_at),
      last_seen_at: accountSecuritySafeTimestamp(value.last_seen_at),
      expires_at: accountSecuritySafeTimestamp(value.expires_at)
    };
  }

  function accountSecurityLoginMethodProjection(value) {
    const source = value && typeof value === "object" ? value : {};
    const password = source.password && typeof source.password === "object"
      ? { available: source.password.available === true }
      : { available: false };
    const seen = new Set();
    const oauth = Array.isArray(source.oauth)
      ? source.oauth.map((item) => {
        const provider = String(item && item.provider || "").trim().toLowerCase();
        if (!ACCOUNT_SECURITY_OAUTH_PROVIDERS.has(provider) || seen.has(provider)) return null;
        seen.add(provider);
        return {
          provider,
          linked: item && item.linked === true,
          enabled: item && item.enabled === true,
          can_unlink: item && item.can_unlink === true
        };
      }).filter(Boolean).slice(0, 4)
      : [];
    const usableFactorCount = Number(source.usable_factor_count);
    const rawContact = source.contact && typeof source.contact === "object" ? source.contact : {};
    const contactState = String(rawContact.state || "").trim();
    const contactProvider = String(rawContact.provider || "").trim().toLowerCase();
    const rawEmailVerification = source.email_verification && typeof source.email_verification === "object"
      ? source.email_verification
      : {};
    // Fail closed on a malformed/unknown assurance projection.  In
    // particular, do not let a remote string claim an email has been verified
    // and never retain a provider-returned contact email in Portal state.
    const contact = contactState === "verified_oauth"
      && ACCOUNT_SECURITY_CONTACT_PROVIDERS.has(contactProvider)
      && rawContact.verified === true
      ? { state: "verified_oauth", provider: contactProvider, verified: true }
      : contactState === "verified_email_link"
        && contactProvider === "email_link"
        && rawContact.verified === true
        ? { state: "verified_email_link", provider: "email_link", verified: true }
      : ACCOUNT_SECURITY_CONTACT_STATES.has(contactState)
        ? { state: contactState, provider: "", verified: false }
        : { state: "unavailable", provider: "", verified: false };
    const deliveryAvailable = rawEmailVerification.available === true;
    const canStartVerification = deliveryAvailable
      && rawEmailVerification.can_start === true
      && password.available === true
      && contact.verified !== true;
    const pendingVerification = canStartVerification
      && rawEmailVerification.pending === true;
    return {
      password,
      oauth,
      usable_factor_count: Number.isInteger(usableFactorCount) && usableFactorCount >= 0 && usableFactorCount <= 16
        ? usableFactorCount
        : 0,
      contact,
      email_verification: {
        available: deliveryAvailable,
        can_start: canStartVerification,
        pending: pendingVerification
      }
    };
  }

  function accountSecurityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath) {
    return requestEpoch === accountSecurityHydrationEpoch
      && sessionEpoch === accountSecuritySessionEpoch
      && currentPortalPath() === expectedPath
      && expectedPath === "/account/security"
      && Boolean(base().session && base().session.authenticated === true);
  }

  function clearAccountSecurityPasswordInputs() {
    document.querySelectorAll("[data-account-security-secret]").forEach((input) => {
      input.value = "";
    });
  }

  function clearAccountSecurityMfaInputs() {
    document.querySelectorAll("[data-account-security-mfa-secret]").forEach((input) => {
      input.value = "";
    });
  }

  function applyAccountSecuritySessionRotation(data) {
    const csrfToken = data && typeof data.csrf_token === "string" ? data.csrf_token : "";
    // The token is opaque, short-lived in Portal memory and never copied to
    // a URL, browser storage, form draft, log or toast. A normal hydrate()
    // immediately re-reads the signed session after this narrow update.
    if (!csrfToken || csrfToken.length > 4096 || /[\u0000-\u001f\u007f]/.test(csrfToken)) return false;
    merge({
      session: { ...(base().session || {}), csrfToken, csrfReady: true }
    });
    return true;
  }

  async function hydrateAccountSecurity() {
    const requestEpoch = ++accountSecurityHydrationEpoch;
    const sessionEpoch = accountSecuritySessionEpoch;
    const expectedPath = currentPortalPath();
    try {
      const mfaEnabled = base().totpMfaEnabled === true;
      const [sessionsResult, loginMethodsResult, mfaResult] = await Promise.all([
        api("/auth/security/sessions"),
        api("/auth/security/login-methods"),
        mfaEnabled ? api("/auth/mfa/status") : Promise.resolve({ data: { mfa: {} } })
      ]);
      if (!accountSecurityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      const rawSessions = sessionsResult.data && Array.isArray(sessionsResult.data.sessions) ? sessionsResult.data.sessions : [];
      const sessions = rawSessions.map(accountSecuritySessionProjection).filter(Boolean).slice(0, 20);
      const loginMethods = accountSecurityLoginMethodProjection(loginMethodsResult.data && loginMethodsResult.data.login_methods);
      const mfa = mfaEnabled
        ? accountSecurityMfaProjection(mfaResult.data && mfaResult.data.mfa)
        : accountSecurityMfaProjection({});
      if (!accountSecurityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      merge({
        accountSecurity: { sessions, loginMethods, mfa, readState: "read_only" },
        // A normal refresh intentionally discards a partially displayed
        // enrollment key and one-time recovery codes. They can be revealed
        // only by their respective just-completed server action.
        mfaEnrollment: {},
        mfaRecoveryCodes: [],
        pageStates: { ...(base().pageStates || {}), "/account/security": "read_only" }
      });
      return { sessions, loginMethods };
    } catch (_) {
      // A failed owner-scoped read must never retain a previous account's
      // session metadata or factor availability, and it must not invent a
      // browser-only recovery/security state.
      if (!accountSecurityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      merge({
        accountSecurity: { sessions: [], loginMethods: {}, mfa: accountSecurityMfaProjection({}), readState: "guarded" },
        mfaEnrollment: {},
        mfaRecoveryCodes: [],
        pageStates: { ...(base().pageStates || {}), "/account/security": "guarded" }
      });
      return null;
    }
  }

  function workspaceDraftRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath) {
    return requestEpoch === workspaceDraftHydrationEpoch
      && sessionEpoch === workspaceDraftSessionEpoch
      && currentPortalPath() === expectedPath
      && ["/workspace", "/dashboard"].includes(expectedPath)
      && Boolean(base().session && base().session.authenticated === true);
  }

  async function hydrateAccountActivity() {
    const requestEpoch = ++accountActivityHydrationEpoch;
    const sessionEpoch = accountActivitySessionEpoch;
    const expectedPath = currentPortalPath();
    try {
      const result = await api("/account/activity");
      if (!accountActivityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return [];
      const items = result.data && Array.isArray(result.data.items) ? result.data.items.slice(0, 50) : [];
      if (!accountActivityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return [];
      merge({
        accountActivity: items,
        pageStates: { ...(base().pageStates || {}), "/account/activity": result.status || "read_only" }
      });
      return items;
    } catch (_) {
      // Do not retain another account's activity or invent browser history.
      // An empty history is the only safe fallback for a failed signed read.
      if (!accountActivityRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return [];
      merge({ accountActivity: [], pageStates: { ...(base().pageStates || {}), "/account/activity": "guarded" } });
      return [];
    }
  }

  // Data Control Center has an intentionally small Web-only public contract.
  // These constants mirror the server allow-lists for client-side projection
  // only; server-side ownership, scope, transitions and authority remain
  // canonical. Never reuse Bot data-deletion state or a generic bridge result.
  const DATA_CONTROLS_POLICY_VERSION = "web_data_controls_v1";
  const DATA_CONTROLS_SCOPE_KEY = "web_authoring_only";
  const DATA_CONTROLS_ERASURE_ACKNOWLEDGEMENT = "REQUEST WEB AUTHORING ERASURE";
  const DATA_CONTROLS_CANCEL_ACKNOWLEDGEMENT = "CANCEL WEB ERASURE REQUEST";
  const DATA_CONTROLS_LIST_LIMIT = 20;
  const DATA_CONTROLS_CATEGORY_KEYS = new Set([
    "account_profile", "memory_center", "prompt_library", "workboard"
  ]);
  const DATA_CONTROLS_CATEGORY_ORDER = Object.freeze([
    "account_profile", "memory_center", "prompt_library", "workboard"
  ]);
  const DATA_CONTROLS_REQUEST_STATES = new Set([
    "awaiting_review", "identity_verification_pending", "cancelled", "closed"
  ]);

  function validDataControlsRequestId(value) {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || "").trim());
  }

  function dataControlsSafeInteger(value, minimum, maximum) {
    const number = Number(value);
    return Number.isSafeInteger(number) && number >= minimum && number <= maximum ? number : null;
  }

  function dataControlsSafeTimestamp(value) {
    const text = typeof value === "string" ? value.trim() : "";
    return text && text.length <= 80 && !/[\u0000-\u001f\u007f]/.test(text) ? text : "";
  }

  function dataControlsBoundaryIsSafe(value) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : null;
    if (!data
      || data.execution !== "web_data_control_request_only"
      || data.data_origin !== "explicit_web_owned_authoring_projection"
      || data.policy_version !== DATA_CONTROLS_POLICY_VERSION) return false;
    return [
      "bot_called", "telegram_data_included", "bridge_called", "wallet_mutated",
      "payment_processed", "provider_called", "job_created", "job_or_asset_data_included",
      "account_deleted", "files_deleted", "support_evidence_deleted", "external_notification_sent"
    ].every((key) => data[key] === false);
  }

  function dataControlsRequestProjection(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const id = String(source.id || "").trim().toLowerCase();
    const state = String(source.state || "").trim().toLowerCase();
    const revision = dataControlsSafeInteger(source.revision, 1, 1000000);
    const requestedAt = dataControlsSafeTimestamp(source.requested_at);
    const updatedAt = dataControlsSafeTimestamp(source.updated_at);
    const cancelledAt = source.cancelled_at === null ? null : dataControlsSafeTimestamp(source.cancelled_at);
    if (!validDataControlsRequestId(id)
      || source.scope_key !== DATA_CONTROLS_SCOPE_KEY
      || !DATA_CONTROLS_REQUEST_STATES.has(state)
      || revision === null
      || !requestedAt
      || !updatedAt
      || (source.cancelled_at !== null && !cancelledAt)
      || source.automatic_deletion !== false
      || source.human_review_required !== true) return null;
    return {
      id,
      scopeKey: DATA_CONTROLS_SCOPE_KEY,
      state,
      revision,
      requestedAt,
      updatedAt,
      cancelledAt,
      automaticDeletion: false,
      humanReviewRequired: true
    };
  }

  function dataControlsSummaryProjection(value) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const inventory = data.inventory && typeof data.inventory === "object" && !Array.isArray(data.inventory) ? data.inventory : {};
    const policy = inventory.erasure_policy && typeof inventory.erasure_policy === "object" ? inventory.erasure_policy : {};
    if (!dataControlsBoundaryIsSafe(data)
      || inventory.policy_version !== DATA_CONTROLS_POLICY_VERSION
      || inventory.scope_key !== DATA_CONTROLS_SCOPE_KEY
      || policy.automatic_deletion !== false
      || policy.human_review_required !== true
      || policy.scope !== DATA_CONTROLS_SCOPE_KEY
      || policy.account_or_file_deletion !== false) return null;
    const rawCategories = Array.isArray(inventory.categories) ? inventory.categories : [];
    if (rawCategories.length !== DATA_CONTROLS_CATEGORY_ORDER.length) return null;
    const categories = [];
    for (const key of DATA_CONTROLS_CATEGORY_ORDER) {
      const item = rawCategories.find((candidate) => candidate && candidate.key === key);
      const recordCount = item ? dataControlsSafeInteger(item.record_count, 0, 100000000) : null;
      if (!item || !DATA_CONTROLS_CATEGORY_KEYS.has(key)
        || recordCount === null
        || item.export_available !== true
        || typeof item.erasure_request_available !== "boolean") return null;
      categories.push({
        key,
        recordCount,
        exportAvailable: true,
        erasureRequestAvailable: item.erasure_request_available === true
      });
    }
    const authoringRecordCount = dataControlsSafeInteger(inventory.authoring_record_count, 0, 100000000);
    const rawCounts = data.request_counts && typeof data.request_counts === "object" ? data.request_counts : {};
    const requestCounts = {};
    for (const state of DATA_CONTROLS_REQUEST_STATES) {
      const count = dataControlsSafeInteger(rawCounts[state], 0, 100000000);
      if (count === null) return null;
      requestCounts[state] = count;
    }
    if (authoringRecordCount === null) return null;
    return {
      policyVersion: DATA_CONTROLS_POLICY_VERSION,
      scopeKey: DATA_CONTROLS_SCOPE_KEY,
      categories,
      authoringRecordCount,
      requestCounts,
      automaticDeletion: false,
      humanReviewRequired: true
    };
  }

  function dataControlsListingProjection(value, requestedOffset) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const offset = dataControlsSafeInteger(requestedOffset, 0, 5000);
    const rawItems = Array.isArray(data.items) ? data.items : null;
    if (!dataControlsBoundaryIsSafe(data) || offset === null || !rawItems || rawItems.length > DATA_CONTROLS_LIST_LIMIT) return null;
    const items = rawItems.map(dataControlsRequestProjection);
    if (items.some((item) => !item)) return null;
    const hasMore = data.has_more === true;
    const nextOffset = data.next_offset === null ? null : dataControlsSafeInteger(data.next_offset, 0, 5000);
    if ((hasMore && (nextOffset === null || nextOffset !== offset + DATA_CONTROLS_LIST_LIMIT))
      || (!hasMore && nextOffset !== null)) return null;
    return {
      items,
      listing: { limit: DATA_CONTROLS_LIST_LIMIT, offset, hasMore, nextOffset }
    };
  }

  // Governance & Internal Documents is intentionally a narrow, Web-native
  // staff workspace. It does not adapt Bot `/admin_docs`, Telegram files,
  // generic bridge state, PayOS/Xu, providers, customer data or external
  // delivery. These small projections are defensive presentation checks; the
  // admin/session/CSRF/revision/idempotency checks remain authoritative in the
  // dedicated server router.
  const GOVERNANCE_DOCUMENT_STATES = new Set(["draft", "in_review", "approved", "archived"]);
  const GOVERNANCE_DOCUMENT_SCOPES = new Set(["all", "mine", "review"]);
  const GOVERNANCE_RETENTION_LABELS = new Set(["manual_review", "3_years", "5_years", "permanent"]);
  const GOVERNANCE_CONFIDENTIALITY_LEVELS = new Set(["internal", "confidential", "restricted"]);
  const GOVERNANCE_DOCUMENT_LIST_LIMIT = 25;
  const GOVERNANCE_ACKNOWLEDGEMENTS = Object.freeze({
    "submit-review": "SUBMIT GOVERNANCE DOCUMENT FOR REVIEW",
    approve: "APPROVE GOVERNANCE DOCUMENT",
    reject: "REJECT GOVERNANCE DOCUMENT",
    archive: "ARCHIVE GOVERNANCE DOCUMENT",
    restore: "RESTORE GOVERNANCE DOCUMENT"
  });

  function governanceSafeInteger(value, minimum, maximum) {
    const number = Number(value);
    return Number.isSafeInteger(number) && number >= minimum && number <= maximum ? number : null;
  }

  function governanceSafeText(value, minimum, maximum) {
    const text = typeof value === "string" ? value.trim() : "";
    return text.length >= minimum && text.length <= maximum && !/[\u0000-\u001f\u007f]/.test(text) ? text : "";
  }

  function governanceSafeToken(value) {
    const token = governanceSafeText(value, 1, 80).toLowerCase();
    return /^[a-z][a-z0-9_-]{0,79}$/.test(token) ? token : "";
  }

  function governanceRetentionLabel(value) {
    const label = governanceSafeText(value, 1, 32).toLowerCase();
    return GOVERNANCE_RETENTION_LABELS.has(label) ? label : "";
  }

  function governanceSafeTimestamp(value) {
    return governanceSafeText(value, 1, 80);
  }

  function governanceBoundaryIsSafe(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const boundary = source.boundary && typeof source.boundary === "object" && !Array.isArray(source.boundary)
      ? source.boundary
      : source;
    // `external_effects: none` is the explicit backend contract. Do not infer
    // a safe outcome from a 200 response, an admin role in browser state, or a
    // generic endpoint that happens to have similarly named fields.
    return boundary.external_effects === "none";
  }

  function governanceResultData(result) {
    const data = result && result.data && typeof result.data === "object" && !Array.isArray(result.data) ? result.data : {};
    // Most Web modules place their boundary in `data`, while this router may
    // expose it at the envelope level. Copy only this fixed safety metadata
    // into an ephemeral projection; never spread the whole response or retain
    // headers/request identifiers in Portal state.
    if (!data.boundary && result && result.boundary && typeof result.boundary === "object" && !Array.isArray(result.boundary)) {
      return { ...data, boundary: result.boundary };
    }
    return data;
  }

  function governanceDocumentId(value) {
    const id = String(value || "").trim().toLowerCase();
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(id) ? id : "";
  }

  function governanceTags(value) {
    if (!Array.isArray(value) || value.length > 16) return null;
    const seen = new Set();
    const tags = [];
    for (const item of value) {
      const tag = governanceSafeText(item, 1, 64);
      const key = tag.toLowerCase();
      if (!tag || seen.has(key)) return null;
      seen.add(key);
      tags.push(tag);
    }
    return tags;
  }

  function governancePermissions(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const keys = ["can_update", "can_submit", "can_review", "can_archive", "can_restore"];
    if (!keys.every((key) => typeof source[key] === "boolean")) return null;
    return {
      canUpdate: source.can_update === true,
      canSubmit: source.can_submit === true,
      canReview: source.can_review === true,
      canArchive: source.can_archive === true,
      canRestore: source.can_restore === true
    };
  }

  function governanceDocumentProjection(value, detail) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const id = governanceDocumentId(source.id);
    const department = governanceSafeToken(source.department);
    const documentType = governanceSafeToken(source.document_type);
    const title = governanceSafeText(source.title, 1, 240);
    const summary = source.summary === null || source.summary === undefined ? "" : governanceSafeText(source.summary, 0, 1600);
    const state = String(source.state || "").trim().toLowerCase();
    const revision = governanceSafeInteger(source.revision, 1, 1000000);
    const createdAt = governanceSafeTimestamp(source.created_at);
    const updatedAt = governanceSafeTimestamp(source.updated_at);
    const submittedAt = source.submitted_at === null ? null : governanceSafeTimestamp(source.submitted_at);
    const reviewedAt = source.reviewed_at === null ? null : governanceSafeTimestamp(source.reviewed_at);
    const archivedAt = source.archived_at === null ? null : governanceSafeTimestamp(source.archived_at);
    const ownership = source.ownership === "own" || source.ownership === "other" ? source.ownership : "";
    const retentionLabel = governanceRetentionLabel(source.retention_label || "manual_review");
    const confidentialityLevel = governanceSafeToken(source.confidentiality_level || "internal");
    const tags = governanceTags(source.tags || []);
    const permissions = governancePermissions(source.permissions);
    if (!id || !department || !documentType || !title || summary === "" && source.summary !== "" && source.summary !== null && source.summary !== undefined
      || !GOVERNANCE_DOCUMENT_STATES.has(state) || revision === null || !createdAt || !updatedAt
      || (source.submitted_at !== null && !submittedAt) || (source.reviewed_at !== null && !reviewedAt)
      || (source.archived_at !== null && !archivedAt) || !ownership || !tags || !permissions
      || !GOVERNANCE_RETENTION_LABELS.has(retentionLabel) || !GOVERNANCE_CONFIDENTIALITY_LEVELS.has(confidentialityLevel)) return null;
    const document = {
      id, department, documentType, title, summary, tags, state, revision,
      retentionLabel, confidentialityLevel, createdAt, updatedAt, submittedAt, reviewedAt, archivedAt, ownership, permissions
    };
    if (!detail) return document;
    const body = typeof source.body === "string" && source.body.length <= 48000 && !/[\u0000]/.test(source.body) ? source.body : "";
    const reviewNote = source.review_note === null || source.review_note === undefined ? "" : governanceSafeText(source.review_note, 0, 1600);
    if (!body || reviewNote === "" && source.review_note !== "" && source.review_note !== null && source.review_note !== undefined) return null;
    return { ...document, body, reviewNote };
  }

  function governanceCatalogEntries(value) {
    const entries = [];
    const seen = new Set();
    const push = (rawKey, rawLabel) => {
      const key = governanceSafeToken(rawKey);
      const label = governanceSafeText(rawLabel, 1, 120) || key;
      if (!key || seen.has(key)) return;
      seen.add(key);
      entries.push({ key, label });
    };
    if (Array.isArray(value)) {
      value.slice(0, 60).forEach((item) => {
        if (typeof item === "string") push(item, item);
        else if (item && typeof item === "object") push(item.key || item.value || item.id, item.label || item.name || item.title || item.key || item.value || item.id);
      });
    } else if (value && typeof value === "object") {
      Object.entries(value).slice(0, 60).forEach(([key, label]) => {
        if (label && typeof label === "object") push(key, label.label || label.name || label.title || key);
        else push(key, String(label || key));
      });
    }
    return entries;
  }

  function governancePolicyProjection(value) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const source = data.policy && typeof data.policy === "object" && !Array.isArray(data.policy) ? data.policy : data;
    if (!governanceBoundaryIsSafe(data) && !governanceBoundaryIsSafe(source)) return null;
    const rawDepartments = Array.isArray(source.departments) ? source.departments : [];
    const departments = [];
    const documentTypes = [];
    const departmentTypes = {};
    const seenDepartments = new Set();
    const seenTypes = new Set();
    for (const rawDepartment of rawDepartments.slice(0, 12)) {
      const item = rawDepartment && typeof rawDepartment === "object" ? rawDepartment : {};
      const key = governanceSafeToken(item.key);
      const label = governanceSafeText(item.label, 1, 120) || key;
      const types = governanceCatalogEntries(item.document_types);
      if (!key || seenDepartments.has(key) || !types.length) return null;
      seenDepartments.add(key);
      departments.push({ key, label });
      departmentTypes[key] = types.map((entry) => entry.key);
      types.forEach((entry) => {
        if (seenTypes.has(entry.key)) return;
        seenTypes.add(entry.key);
        documentTypes.push(entry);
      });
    }
    const lifecycleSource = source.lifecycle && typeof source.lifecycle === "object" && !Array.isArray(source.lifecycle)
      ? source.lifecycle.states
      : source.lifecycle;
    const lifecycle = (Array.isArray(lifecycleSource) ? lifecycleSource : [])
      .map((item) => governanceSafeToken(typeof item === "string" ? item : item && item.key))
      .filter((item) => GOVERNANCE_DOCUMENT_STATES.has(item));
    const acknowledgementSource = source.acknowledgements && typeof source.acknowledgements === "object" ? source.acknowledgements : {};
    const acknowledgements = {};
    Object.entries(GOVERNANCE_ACKNOWLEDGEMENTS).forEach(([action, expected]) => {
      const candidate = String(acknowledgementSource[action] || acknowledgementSource[action.replace("-", "_")] || expected).trim();
      acknowledgements[action] = candidate === expected ? expected : "";
    });
    const limits = source.limits && typeof source.limits === "object" ? source.limits : {};
    const retentionLabels = (Array.isArray(limits.retention_labels) ? limits.retention_labels : [])
      .map(governanceRetentionLabel)
      .filter((item, index, items) => GOVERNANCE_RETENTION_LABELS.has(item) && items.indexOf(item) === index);
    const confidentialityLevels = (Array.isArray(limits.confidentiality_levels) ? limits.confidentiality_levels : [])
      .map(governanceSafeToken)
      .filter((item, index, items) => GOVERNANCE_CONFIDENTIALITY_LEVELS.has(item) && items.indexOf(item) === index);
    if (!departments.length || !documentTypes.length || lifecycle.length !== GOVERNANCE_DOCUMENT_STATES.size
      || !Object.values(acknowledgements).every(Boolean)
      || retentionLabels.length !== GOVERNANCE_RETENTION_LABELS.size
      || confidentialityLevels.length !== GOVERNANCE_CONFIDENTIALITY_LEVELS.size) return null;
    return {
      departments, documentTypes, departmentTypes, retentionLabels, confidentialityLevels,
      lifecycle: [...new Set(lifecycle)],
      acknowledgements,
      limits: {
        titleMax: governanceSafeInteger(limits.title_characters || limits.title_max || limits.title_max_length, 1, 1000) || 180,
        summaryMax: governanceSafeInteger(limits.summary_characters || limits.summary_max || limits.summary_max_length, 0, 10000) || 1200,
        bodyMax: governanceSafeInteger(limits.body_characters || limits.body_max || limits.body_max_length, 1, 50000) || 48000,
        reviewNoteMax: governanceSafeInteger(limits.review_note_characters, 0, 10000) || 1600,
        tagsMax: governanceSafeInteger(limits.tags || limits.tags_max || limits.tag_count_max, 0, 100) || 12
      }
    };
  }

  function governanceSummaryProjection(value) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const source = data.summary && typeof data.summary === "object" && !Array.isArray(data.summary) ? data.summary : data;
    if (!governanceBoundaryIsSafe(data) && !governanceBoundaryIsSafe(source)) return null;
    const rawCounts = source.by_state && typeof source.by_state === "object"
      ? source.by_state
      : (source.counts && typeof source.counts === "object" ? source.counts : {});
    const counts = {};
    GOVERNANCE_DOCUMENT_STATES.forEach((state) => {
      counts[state] = governanceSafeInteger(rawCounts[state], 0, 100000000);
      if (counts[state] === null) counts[state] = 0;
    });
    return {
      counts,
      ownDocuments: governanceSafeInteger(source.own_documents, 0, 100000000) || 0,
      reviewable: governanceSafeInteger(source.reviewable_by_current_admin, 0, 100000000) || 0
    };
  }

  function governanceDocumentFilter(value) {
    const source = value && typeof value === "object" ? value : {};
    const department = source.department ? governanceSafeToken(source.department) : "";
    const documentType = source.document_type ? governanceSafeToken(source.document_type) : "";
    const state = String(source.state || "all").trim().toLowerCase();
    const scope = String(source.scope || "all").trim().toLowerCase();
    const q = String(source.q || "").replace(/\s+/g, " ").trim();
    if ((source.department && !department) || (source.document_type && !documentType)
      || (state !== "all" && !GOVERNANCE_DOCUMENT_STATES.has(state))
      || !GOVERNANCE_DOCUMENT_SCOPES.has(scope) || q.length > 120 || /[\u0000-\u001f\u007f]/.test(q)) {
      throw new Error("Bộ lọc Governance Documents không hợp lệ.");
    }
    return { department, document_type: documentType, state, scope, q };
  }

  function governanceListingProjection(value, filter, offset) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const source = data.documents && Array.isArray(data.documents) ? data : (data.items && Array.isArray(data.items) ? data : {});
    const items = Array.isArray(source.documents) ? source.documents : source.items;
    const pagination = data.pagination && typeof data.pagination === "object" ? data.pagination : data;
    const requestedOffset = governanceSafeInteger(offset, 0, 5000);
    if (!governanceBoundaryIsSafe(data) || !items || items.length > GOVERNANCE_DOCUMENT_LIST_LIMIT || requestedOffset === null) return null;
    const documents = items.map((item) => governanceDocumentProjection(item, false));
    if (documents.some((item) => !item)) return null;
    const hasMore = pagination.has_more === true || pagination.hasMore === true;
    const nextRaw = pagination.next_offset === undefined ? pagination.nextOffset : pagination.next_offset;
    const nextOffset = nextRaw === null || nextRaw === undefined ? null : governanceSafeInteger(nextRaw, 0, 5000);
    if ((hasMore && (nextOffset === null || nextOffset <= requestedOffset)) || (!hasMore && nextOffset !== null)) return null;
    return {
      documents,
      listing: { ...filter, limit: GOVERNANCE_DOCUMENT_LIST_LIMIT, offset: requestedOffset, hasMore, nextOffset }
    };
  }

  function governanceDetailProjection(value) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const document = data.document && typeof data.document === "object" ? data.document : null;
    return governanceBoundaryIsSafe(data) && document ? governanceDocumentProjection(document, true) : null;
  }

  function governanceVersionProjection(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const revision = governanceSafeInteger(source.revision, 1, 1000000);
    const state = String(source.state || "").trim().toLowerCase();
    const createdAt = governanceSafeTimestamp(source.created_at || source.updated_at);
    const action = governanceSafeToken(source.action);
    return revision !== null && action && GOVERNANCE_DOCUMENT_STATES.has(state) && createdAt
      ? { revision, action, state, createdAt }
      : null;
  }

  function governanceEventProjection(value) {
    const source = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const action = governanceSafeToken(source.action);
    const state = String(source.to_state || source.state || "").trim().toLowerCase();
    const revision = governanceSafeInteger(source.revision, 1, 1000000);
    const createdAt = governanceSafeTimestamp(source.created_at);
    return action && GOVERNANCE_DOCUMENT_STATES.has(state) && revision !== null && createdAt
      ? { action, state, revision, createdAt }
      : null;
  }

  function governanceChildListProjection(value, key, projection) {
    const data = value && typeof value === "object" && !Array.isArray(value) ? value : {};
    const rawItems = Array.isArray(data[key]) ? data[key] : (Array.isArray(data.items) ? data.items : null);
    if (!governanceBoundaryIsSafe(data) || !rawItems || rawItems.length > 200) return null;
    const items = rawItems.map(projection);
    return items.some((item) => !item) ? null : items;
  }

  function governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, detail) {
    return requestEpoch === (detail ? governanceDocumentDetailHydrationEpoch : governanceDocumentsHydrationEpoch)
      && sessionEpoch === governanceDocumentsSessionEpoch
      && currentPortalPath() === expectedPath
      && isNativeGovernanceDocumentsPath(expectedPath)
      && Boolean(base().session && base().session.authenticated === true)
      && base().governanceDocumentsEnabled === true
      && base().governanceAdminSessionHint === true;
  }

  function governanceOffset(value) {
    const offset = governanceSafeInteger(value, 0, 5000);
    return offset === null ? 0 : offset;
  }

  function governanceDocumentsPath(filter, offset) {
    const parameters = new URLSearchParams({
      state: filter.state, scope: filter.scope, limit: String(GOVERNANCE_DOCUMENT_LIST_LIMIT), offset: String(governanceOffset(offset))
    });
    if (filter.department) parameters.set("department", filter.department);
    if (filter.document_type) parameters.set("document_type", filter.document_type);
    if (filter.q) parameters.set("q", filter.q);
    return `/admin/governance/documents?${parameters.toString()}`;
  }

  function clearGovernanceProjection(state) {
    const currentPath = currentPortalPath();
    const pageState = state === "loading" ? "processing" : "guarded";
    merge({
      governanceServerAdmin: false,
      governancePolicy: {}, governanceSummary: {}, governanceDocuments: [],
      governanceDocumentListing: { department: "", document_type: "", state: "all", scope: "all", q: "", limit: GOVERNANCE_DOCUMENT_LIST_LIMIT, offset: 0, hasMore: false, nextOffset: null },
      governanceDocumentDetail: {}, governanceDocumentVersions: [], governanceDocumentEvents: [], governanceReadState: state || "guarded",
      pageStates: {
        ...(base().pageStates || {}),
        "/admin/governance": pageState,
        "/admin/governance/documents": pageState,
        [currentPath]: pageState
      }
    });
  }

  async function hydrateGovernanceDocuments(filterValue, offsetValue) {
    const requestEpoch = ++governanceDocumentsHydrationEpoch;
    const sessionEpoch = governanceDocumentsSessionEpoch;
    const expectedPath = currentPortalPath();
    const priorListing = base().governanceDocumentListing && typeof base().governanceDocumentListing === "object" ? base().governanceDocumentListing : {};
    const filter = governanceDocumentFilter(filterValue === undefined ? priorListing : filterValue);
    const offset = governanceOffset(offsetValue === undefined ? priorListing.offset : offsetValue);
    if (!governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, false)) return null;
    clearGovernanceProjection("loading");
    try {
      const [policyResult, summaryResult, documentsResult] = await Promise.all([
        api("/admin/governance/policy"), api("/admin/governance/summary"), api(governanceDocumentsPath(filter, offset))
      ]);
      if (!governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, false)) return null;
      const policy = governancePolicyProjection(governanceResultData(policyResult));
      const summary = governanceSummaryProjection(governanceResultData(summaryResult));
      const page = governanceListingProjection(governanceResultData(documentsResult), filter, offset);
      if (!policy || !summary || !page) throw new Error("Governance server chưa trả projection nội bộ hợp lệ.");
      merge({
        governanceServerAdmin: true, governancePolicy: policy, governanceSummary: summary,
        governanceDocuments: page.documents, governanceDocumentListing: page.listing,
        governanceDocumentDetail: {}, governanceDocumentVersions: [], governanceDocumentEvents: [],
        governanceReadState: "read_only",
        pageStates: { ...(base().pageStates || {}), "/admin/governance": "read_only", "/admin/governance/documents": "read_only", [expectedPath]: "read_only" }
      });
      return { policy, summary, ...page };
    } catch (_) {
      if (!governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, false)) return null;
      clearGovernanceProjection("guarded");
      return null;
    }
  }

  async function hydrateGovernanceDocumentDetail(documentId) {
    const id = governanceDocumentId(documentId);
    const requestEpoch = ++governanceDocumentDetailHydrationEpoch;
    const sessionEpoch = governanceDocumentsSessionEpoch;
    const expectedPath = currentPortalPath();
    if (!id || !governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, true)
      || governanceDocumentIdFromPath(expectedPath) !== id) return null;
    clearGovernanceProjection("loading");
    try {
      const encoded = encodeURIComponent(id);
      const [policyResult, summaryResult, documentResult, versionsResult, eventsResult] = await Promise.all([
        api("/admin/governance/policy"), api("/admin/governance/summary"),
        api(`/admin/governance/documents/${encoded}`), api(`/admin/governance/documents/${encoded}/versions`), api(`/admin/governance/documents/${encoded}/events`)
      ]);
      if (!governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, true)) return null;
      const policy = governancePolicyProjection(governanceResultData(policyResult));
      const summary = governanceSummaryProjection(governanceResultData(summaryResult));
      const document = governanceDetailProjection(governanceResultData(documentResult));
      const versions = governanceChildListProjection(governanceResultData(versionsResult), "versions", governanceVersionProjection);
      const events = governanceChildListProjection(governanceResultData(eventsResult), "events", governanceEventProjection);
      if (!policy || !summary || !document || document.id !== id || !versions || !events) throw new Error("Governance document chưa trả chi tiết hợp lệ.");
      merge({
        governanceServerAdmin: true, governancePolicy: policy, governanceSummary: summary, governanceDocuments: [],
        governanceDocumentListing: { department: "", document_type: "", state: "all", scope: "all", q: "", limit: GOVERNANCE_DOCUMENT_LIST_LIMIT, offset: 0, hasMore: false, nextOffset: null },
        governanceDocumentDetail: document, governanceDocumentVersions: versions, governanceDocumentEvents: events,
        governanceReadState: "read_only", pageStates: { ...(base().pageStates || {}), [expectedPath]: "read_only" }
      });
      return { policy, summary, document, versions, events };
    } catch (_) {
      if (!governanceRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath, true)) return null;
      clearGovernanceProjection("guarded");
      return null;
    }
  }

  function governanceWriteReceipt(result, operation, documentId) {
    const data = governanceResultData(result);
    const document = data.document && typeof data.document === "object" ? data.document : {};
    const id = governanceDocumentId(document.id);
    const revision = governanceSafeInteger(document.revision, 1, 1000000);
    const state = String(document.state || "").trim().toLowerCase();
    const updatedAt = governanceSafeTimestamp(document.updated_at);
    // The server's audited action label is intentionally treated as opaque
    // metadata. Validate that it is bounded when supplied, but do not invent
    // a browser-side mapping from lifecycle labels to audit terminology.
    if (!governanceBoundaryIsSafe(data) || !id || (documentId && id !== documentId)
      || revision === null || !GOVERNANCE_DOCUMENT_STATES.has(state) || !updatedAt
      || (data.action !== undefined && !governanceSafeToken(data.action))) {
      throw new Error("Governance server chưa xác nhận receipt write nội bộ hợp lệ.");
    }
    return { id, revision, state, updatedAt };
  }

  function governanceCreatePayload(fields, policy) {
    const source = fields && typeof fields === "object" ? fields : {};
    const departments = new Set((policy && policy.departments || []).map((item) => item.key));
    const documentTypes = new Set((policy && policy.documentTypes || []).map((item) => item.key));
    const department = governanceSafeToken(source.department);
    const documentType = governanceSafeToken(source.document_type);
    const title = governanceSafeText(source.title, 3, policy && policy.limits ? policy.limits.titleMax : 240);
    const summary = String(source.summary || "").trim();
    const body = typeof source.body === "string" ? source.body.trim() : "";
    const tagText = String(source.tags || "").trim();
    const tags = tagText ? tagText.split(",").map((item) => item.trim()).filter(Boolean) : [];
    const retentionLabel = governanceRetentionLabel(source.retention_label);
    const confidentialityLevel = governanceSafeToken(source.confidentiality_level);
    const allowedDepartmentTypes = policy && policy.departmentTypes && Array.isArray(policy.departmentTypes[department])
      ? new Set(policy.departmentTypes[department])
      : new Set();
    if (!departments.has(department) || !documentTypes.has(documentType) || !title
      || !allowedDepartmentTypes.has(documentType)
      || summary.length > (policy && policy.limits ? policy.limits.summaryMax : 1600)
      || body.length < 1 || body.length > (policy && policy.limits ? policy.limits.bodyMax : 48000)
      || !governanceTags(tags) || tags.length > (policy && policy.limits ? policy.limits.tagsMax : 12)
      || !(policy && Array.isArray(policy.retentionLabels) && policy.retentionLabels.includes(retentionLabel))
      || !(policy && Array.isArray(policy.confidentialityLevels) && policy.confidentialityLevels.includes(confidentialityLevel))) {
      throw new Error("Nội dung Governance Document không hợp lệ hoặc vượt policy server đã công bố.");
    }
    return { department, document_type: documentType, title, summary, body, tags, retention_label: retentionLabel, confidentiality_level: confidentialityLevel };
  }

  function governanceUpdatePayload(fields, policy) {
    const source = fields && typeof fields === "object" ? fields : {};
    const title = governanceSafeText(source.title, 3, policy && policy.limits ? policy.limits.titleMax : 240);
    const summary = String(source.summary || "").trim();
    const body = typeof source.body === "string" ? source.body.trim() : "";
    const tags = String(source.tags || "").trim() ? String(source.tags).split(",").map((item) => item.trim()).filter(Boolean) : [];
    const retentionLabel = governanceRetentionLabel(source.retention_label);
    const confidentialityLevel = governanceSafeToken(source.confidentiality_level);
    if (!title || summary.length > (policy && policy.limits ? policy.limits.summaryMax : 1600)
      || body.length < 1 || body.length > (policy && policy.limits ? policy.limits.bodyMax : 48000)
      || !governanceTags(tags) || tags.length > (policy && policy.limits ? policy.limits.tagsMax : 12)
      || !(policy && Array.isArray(policy.retentionLabels) && policy.retentionLabels.includes(retentionLabel))
      || !(policy && Array.isArray(policy.confidentialityLevels) && policy.confidentialityLevels.includes(confidentialityLevel))) {
      throw new Error("Nội dung Governance Document không hợp lệ hoặc vượt policy server đã công bố.");
    }
    return { title, summary, body, tags, retention_label: retentionLabel, confidentiality_level: confidentialityLevel };
  }

  async function governanceMutation({ action, route, scope, path, payload, documentId, operation, onSuccess }) {
    const submission = acquireSubmission(scope, JSON.stringify(payload));
    if (!submission) {
      toast("Thao tác Governance đang chờ máy chủ xác nhận. Vui lòng không gửi lại.", "error");
      return null;
    }
    let acknowledged = false;
    setActionBusy(action, route, true);
    try {
      const result = await api(path, {
        method: operation === "update" ? "PATCH" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...payload, idempotency_key: submission.key })
      });
      acknowledged = true;
      const receipt = governanceWriteReceipt(result, operation, documentId);
      if (typeof onSuccess === "function") await onSuccess(receipt, result);
      return receipt;
    } catch (error) {
      acknowledged = Boolean(error && Number.isInteger(error.status) && error.status > 0);
      throw error;
    } finally {
      releaseSubmission(submission);
      if (acknowledged) discardSubmission(scope, submission);
      setActionBusy(action, route, false);
    }
  }

  function dataControlsRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath) {
    return requestEpoch === dataControlsHydrationEpoch
      && sessionEpoch === dataControlsSessionEpoch
      && currentPortalPath() === expectedPath
      && expectedPath === "/account/data-controls"
      && Boolean(base().session && base().session.authenticated === true)
      && base().dataControlsEnabled === true;
  }

  function dataControlsRequestedOffset(value) {
    const offset = dataControlsSafeInteger(value, 0, 5000);
    return offset === null ? 0 : offset;
  }

  function dataControlsListPath(offset) {
    return `/account/data-controls/requests?limit=${DATA_CONTROLS_LIST_LIMIT}&offset=${dataControlsRequestedOffset(offset)}`;
  }

  function clearDataControlsProjection(state) {
    merge({
      dataControlsSummary: {},
      dataControlsRequests: [],
      dataControlsListing: { limit: DATA_CONTROLS_LIST_LIMIT, offset: 0, hasMore: false, nextOffset: null },
      dataControlsReadState: state || "guarded",
      pageStates: { ...(base().pageStates || {}), "/account/data-controls": state === "loading" ? "processing" : "guarded" }
    });
  }

  async function hydrateDataControls(offsetValue) {
    const requestEpoch = ++dataControlsHydrationEpoch;
    const sessionEpoch = dataControlsSessionEpoch;
    const expectedPath = currentPortalPath();
    const priorListing = base().dataControlsListing && typeof base().dataControlsListing === "object" ? base().dataControlsListing : {};
    const offset = dataControlsRequestedOffset(offsetValue === undefined ? priorListing.offset : offsetValue);
    if (!dataControlsRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
    clearDataControlsProjection("loading");
    try {
      const [summaryResult, requestsResult] = await Promise.all([
        api("/account/data-controls/summary"),
        api(dataControlsListPath(offset))
      ]);
      if (!dataControlsRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      if (summaryResult.status !== "read_only" || requestsResult.status !== "read_only") throw new Error("Data Control Center chưa trả trạng thái chỉ đọc hợp lệ.");
      const summary = dataControlsSummaryProjection(summaryResult.data);
      const requestPage = dataControlsListingProjection(requestsResult.data, offset);
      if (!summary || !requestPage) throw new Error("Projection Data Control không hợp lệ.");
      if (!dataControlsRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      merge({
        dataControlsSummary: summary,
        dataControlsRequests: requestPage.items,
        dataControlsListing: requestPage.listing,
        dataControlsReadState: "read_only",
        pageStates: { ...(base().pageStates || {}), "/account/data-controls": "read_only" }
      });
      return { summary, ...requestPage };
    } catch (_) {
      // A failed or schema-drifted private read must clear all prior records;
      // Portal never substitutes a Bot/Telegram deletion state or cache.
      if (!dataControlsRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      clearDataControlsProjection("guarded");
      return null;
    }
  }

  function dataControlsWriteBoundary(value) {
    if (!dataControlsBoundaryIsSafe(value)) throw new Error("Máy chủ chưa trả boundary Data Control hợp lệ.");
    return value;
  }

  async function downloadDataControlsExport() {
    const context = base();
    const csrfToken = context.session && typeof context.session.csrfToken === "string" ? context.session.csrfToken : "";
    if (!(context.session && context.session.authenticated === true && context.dataControlsEnabled === true && csrfToken)) {
      throw new Error("Cần signed Web session, CSRF và Data Control Center đang bật để export.");
    }
    const headers = new Headers({ "Accept": "application/json", "Content-Type": "application/json" });
    headers.set("X-Request-ID", randomKey("web"));
    headers.set("X-CSRF-Token", csrfToken);
    const response = await fetch(`${API}/account/data-controls/export.json`, {
      method: "POST",
      credentials: "same-origin",
      headers,
      body: JSON.stringify({ policy_version: DATA_CONTROLS_POLICY_VERSION, confirm: true })
    });
    if (!response.ok) {
      let payload = {};
      try { payload = await response.json(); } catch (_) { /* sanitized generic error below */ }
      const error = new Error(payload && payload.message ? payload.message : "Máy chủ chưa tạo được export dữ liệu Web.");
      error.status = response.status;
      throw error;
    }
    // A deliberate guarded export response is an envelope with a useful
    // Vietnamese message but can still use HTTP 200. Inspect a clone before
    // downloading so the browser never saves that JSON envelope as though it
    // were the requested private data attachment.
    let guardedEnvelope = null;
    try { guardedEnvelope = await response.clone().json(); } catch (_) { /* the successful attachment is still JSON */ }
    if (guardedEnvelope && guardedEnvelope.ok === false) {
      const error = new Error(guardedEnvelope.message || "Máy chủ chưa tạo được export dữ liệu Web.");
      error.status = response.status;
      throw error;
    }
    const contentType = String(response.headers.get("Content-Type") || "").toLowerCase();
    const cacheControl = String(response.headers.get("Cache-Control") || "").toLowerCase();
    if (!contentType.startsWith("application/json") || !cacheControl.includes("no-store")) {
      throw new Error("Response export không có chính sách attachment riêng tư hợp lệ.");
    }
    const blob = await response.blob();
    if (!(blob.size > 0 && blob.size <= 13 * 1024 * 1024)) {
      throw new Error("Kích thước export không hợp lệ; browser không lưu file một phần.");
    }
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = "toan-aas-web-authoring-data.json";
    anchor.style.display = "none";
    document.body.appendChild(anchor);
    anchor.click();
    anchor.remove();
    // Give the browser a short, bounded window to consume the clicked
    // attachment before releasing its in-memory object URL.
    window.setTimeout(() => URL.revokeObjectURL(url), 1500);
  }

  async function hydrateWorkspaceDrafts(filterValue, offsetValue) {
    const requestEpoch = ++workspaceDraftHydrationEpoch;
    const sessionEpoch = workspaceDraftSessionEpoch;
    const expectedPath = currentPortalPath();
    const isLibraryView = workspaceDraftRouteUsesListView();
    const previousListing = base().workspaceDraftListing && typeof base().workspaceDraftListing === "object" ? base().workspaceDraftListing : {};
    const previousFilters = previousListing.filters && typeof previousListing.filters === "object" ? previousListing.filters : {};
    const previousPagination = previousListing.pagination && typeof previousListing.pagination === "object" ? previousListing.pagination : {};
    const defaultFilter = isLibraryView
      ? { q: "", state: "all", feature_key: "" }
      : { q: "", state: "active", feature_key: "" };
    const filter = workspaceDraftFilterPayload(filterValue === undefined
      ? (isLibraryView ? previousFilters : defaultFilter)
      : filterValue);
    const offset = workspaceDraftListOffset(offsetValue === undefined
      ? (isLibraryView ? previousPagination.offset : 0)
      : offsetValue);
    const limit = isLibraryView ? WORKSPACE_DRAFT_LIST_LIMIT : WORKSPACE_DRAFT_DASHBOARD_LIST_LIMIT;
    const emptyListing = workspaceDraftListingProjection(
      { q: "", state: "all", feature_key: "" }, 0, {}, 0, WORKSPACE_DRAFT_LIST_LIMIT
    );
    try {
      const result = await api(workspaceDraftListPath(filter, offset, limit));
      if (!workspaceDraftRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return [];
      const items = result.data && Array.isArray(result.data.items)
        ? result.data.items.filter((item) => item && validWorkspaceDraftId(item.id)).slice(0, limit)
        : [];
      if (!workspaceDraftRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return [];
      merge({
        workspaceDrafts: items,
        workspaceDraftListing: isLibraryView
          ? workspaceDraftListingProjection(filter, offset, result.data, items.length, limit)
          : emptyListing,
        pageStates: { ...(base().pageStates || {}), [expectedPath]: result.status || "read_only" }
      });
      return items;
    } catch (_) {
      // Do not retain stale data from a different signed account or invent a
      // browser-owned library after a failed owner-scoped read.
      if (!workspaceDraftRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return [];
      merge({
        workspaceDrafts: [],
        workspaceDraftListing: emptyListing,
        pageStates: { ...(base().pageStates || {}), [expectedPath]: "guarded" }
      });
      return [];
    }
  }

  function canonicalRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath) {
    return requestEpoch === canonicalHydrationEpoch
      && sessionEpoch === canonicalSessionEpoch
      && currentPortalPath() === expectedPath
      && Boolean(base().bridge && base().bridge.available === true)
      && Boolean(base().session && base().session.authenticated === true);
  }

  function canonicalAdminDataRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath) {
    return requestEpoch === canonicalAdminDataHydrationEpoch
      && sessionEpoch === canonicalSessionEpoch
      && currentPortalPath() === expectedPath
      && expectedPath.startsWith("/admin")
      && expectedPath !== "/admin/audit"
      && Boolean(base().bridge && base().bridge.available === true)
      && Boolean(base().session && base().session.authenticated === true);
  }

  async function hydrateCanonicalAdminData(path) {
    const expectedPath = String(path || "").split("?")[0];
    if (!expectedPath.startsWith("/admin") || expectedPath === "/admin/audit") return null;
    const requestEpoch = ++canonicalAdminDataHydrationEpoch;
    const sessionEpoch = canonicalSessionEpoch;
    try {
      const admin = await readAdminPath(expectedPath);
      if (!canonicalAdminDataRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      merge({
        adminData: admin.data || {},
        pageStates: {
          ...(base().pageStates || {}),
          [expectedPath]: admin.status === "completed" ? "read_only" : (admin.status || "read_only")
        }
      });
      return admin;
    } catch (error) {
      if (!canonicalAdminDataRequestIsCurrent(requestEpoch, sessionEpoch, expectedPath)) return null;
      // A current failed administrative read must not leave another staff
      // projection or stale operational metadata on the active route.
      merge({
        adminData: {},
        pageStates: { ...(base().pageStates || {}), [expectedPath]: "guarded" }
      });
      throw error;
    }
  }

  async function hydrateCanonicalData() {
    const context = base();
    const path = (context.path || window.location.pathname).split("?")[0];
    // Native authoring workspaces have no generic feature/bridge projection.
    // Return before any canonical endpoint can overwrite their owner-scoped
    // state, including the similarly-prefixed `/voice-studio` route.
    if (isNativePromptStudioPath(path) || isNativeContentPromptPackPath(path) || isNativeContentStudioPath(path) || isNativeChannelStrategyPath(path) || isNativeVoiceStudioPath(path) || isNativeVideoStudioPath(path) || isNativeSubtitleStudioPath(path) || isNativeImageStudioPath(path)) return;
    // Keep the canonical Bot Voice/TTS projection intact, but never let its
    // broad historical `/voice*` matcher absorb the independently owned
    // `/voice-studio` workspace.
    const canonicalBotVoiceRoute = path === "/voice" || path.startsWith("/voice/");
    const canonicalVoicePath = path === "/tts" || path === "/dubbing" || canonicalBotVoiceRoute;
    // Keep the historical Video family exact.  `/video-studio` is not a
    // legacy feature child and must never trigger canonical feature reads.
    const canonicalBotVideoRoute = path === "/video" || path.startsWith("/video/");
    const requestEpoch = ++canonicalHydrationEpoch;
    const sessionEpoch = canonicalSessionEpoch;
    const isCurrent = () => canonicalRequestIsCurrent(requestEpoch, sessionEpoch, path);
    if (!isCurrent()) return null;
    try {
      if (path === "/dashboard") {
        const [wallet, jobs, assets, readiness, tickets] = await Promise.all([
          api("/wallet"), api("/jobs"), api("/assets"), api("/features/status"),
          // A read failure for the optional attention card must not hide the
          // rest of the signed dashboard or turn an unknown ticket state into
          // a browser-side alert.
          api("/support/tickets").catch(() => ({ data: { items: [] } }))
        ]);
        if (!isCurrent()) return null;
        merge({
          wallet: wallet.data || null,
          jobs: jobs.data && jobs.data.items ? jobs.data.items : [],
          assets: assets.data && assets.data.items ? assets.data.items : [],
          tickets: tickets.data && tickets.data.items ? tickets.data.items : [],
          readiness: readiness.data || {},
          pageStates: { ...(base().pageStates || {}), ...featurePageStates(base().catalog || [], readiness.data || {}, base().bridge && base().bridge.featureExecutionFeatures), [path]: "read_only" }
        });
      } else if (path === "/pricing") {
        const pricing = await api("/pricing");
        if (!isCurrent()) return null;
        merge({ pricingCatalog: pricing.data || {}, pageStates: { ...(base().pageStates || {}), [path]: "read_only" } });
      } else if (path === "/packages") {
        const packages = await api("/packages");
        if (!isCurrent()) return null;
        merge({ packageCatalog: packages.data || {}, pageStates: { ...(base().pageStates || {}), [path]: "read_only" } });
      } else if (path === "/membership") {
        const [wallet, packages, readiness] = await Promise.all([api("/wallet"), api("/packages"), api("/features/status")]);
        if (!isCurrent()) return null;
        merge({
          wallet: wallet.data || null,
          packageCatalog: packages.data || {},
          readiness: readiness.data || {},
          pageStates: { ...(base().pageStates || {}), ...featurePageStates(base().catalog || [], readiness.data || {}, base().bridge && base().bridge.featureExecutionFeatures), [path]: "read_only" }
        });
      } else if (path === "/wallet" || path === "/wallet/topup") {
        const [wallet, history, packages] = await Promise.all([api("/wallet"), api("/wallet/history"), api("/packages")]);
        if (!isCurrent()) return null;
        merge({ wallet: wallet.data, walletHistory: history.data && history.data.items ? history.data.items : [], packageCatalog: packages.data || {}, pageStates: path === "/wallet" ? { ...(base().pageStates || {}), [path]: "read_only" } : (base().pageStates || {}) });
      } else if (path === "/jobs") {
        const jobs = await api("/jobs");
        if (!isCurrent()) return null;
        const items = jobs.data && jobs.data.items ? jobs.data.items : [];
        merge({ jobs: items, pageStates: { ...(base().pageStates || {}), [path]: "read_only" } });
        scheduleJobPolling(path, items);
      } else if (path.startsWith("/jobs/")) {
        const jobId = jobIdFromPath(path);
        if (!jobId) return;
        const [job, assets] = await Promise.all([
          api(`/jobs/${encodeURIComponent(jobId)}`),
          api("/assets").catch(() => ({ data: { items: [] } }))
        ]);
        if (!isCurrent()) return null;
        const record = exactJobRecord(job.data, jobId);
        merge({
          jobDetail: record,
          jobAssets: ownedAssetsForJob(record, assets.data && assets.data.items),
          pageStates: { ...(base().pageStates || {}), [path]: job.status || "read_only" }
        });
        scheduleJobPolling(path, record);
      } else if (path === "/voice/outputs") {
        const readiness = await api("/features/status");
        if (!isCurrent()) return null;
        merge({
          readiness: readiness.data || {},
          pageStates: { ...(base().pageStates || {}), ...featurePageStates(base().catalog || [], readiness.data || {}, base().bridge && base().bridge.featureExecutionFeatures) }
        });
      } else if (path === "/assets" || ["/image/assets", "/video/preview", "/video/export", "/music/library", "/music-library", "/music/sfx-library", "/subtitle/formats"].includes(path)) {
        const assets = await api("/assets");
        if (!isCurrent()) return null;
        merge({ assets: assets.data && assets.data.items ? assets.data.items : [], pageStates: { ...(base().pageStates || {}), [path]: "read_only" } });
      } else if (path === "/video/progress") {
        const jobs = await api("/jobs");
        if (!isCurrent()) return null;
        const items = jobs.data && jobs.data.items ? jobs.data.items : [];
        merge({ jobs: items, pageStates: { ...(base().pageStates || {}), [path]: "read_only" } });
        scheduleJobPolling(path, items);
      } else if (path === "/image/resize" || path === "/image/edit" || path === "/image/history") {
        // Native image operations hydrate separately from Asset Vault. Do not
        // request pricing/readiness from the bridge or overwrite the strict
        // server-side guarded/ready state with a generic image feature badge.
      } else if ((path === "/image" || (path.startsWith("/image/") && path !== "/image/history")) || (canonicalBotVideoRoute && !["/video/progress", "/video/preview", "/video/export"].includes(path))) {
        const [pricing, readiness] = await Promise.all([api("/pricing"), api("/features/status")]);
        if (!isCurrent()) return null;
        merge({
          pricingCatalog: pricing.data || {},
          readiness: readiness.data || {},
          pageStates: featurePageStates(base().catalog || [], readiness.data || {}, base().bridge && base().bridge.featureExecutionFeatures)
        });
      } else if (canonicalVoicePath) {
        const [profiles, readiness] = await Promise.all([api("/voice/profiles"), api("/features/status")]);
        if (!isCurrent()) return null;
        merge({
          voiceProfiles: profiles.data && profiles.data.items ? profiles.data.items : [],
          readiness: readiness.data || {},
          pageStates: featurePageStates(base().catalog || [], readiness.data || {}, base().bridge && base().bridge.featureExecutionFeatures)
        });
      } else if (path === "/tickets") {
        const tickets = await api("/support/tickets");
        if (!isCurrent()) return null;
        merge({ tickets: tickets.data && tickets.data.items ? tickets.data.items : [], pageStates: { ...(base().pageStates || {}), [path]: "read_only" } });
      } else if (path === "/admin/audit") {
        // Governance reads the Web-owned redacted Audit Explorer instead of
        // asking the generic Bot bridge to expose a raw audit payload.
        await hydrateAdminAudit();
        if (!isCurrent()) return null;
      } else if (path.startsWith("/admin")) {
        await hydrateCanonicalAdminData(path);
        if (!isCurrent()) return null;
      } else {
        const readiness = await api("/features/status");
        if (!isCurrent()) return null;
        merge({ readiness: readiness.data || {}, pageStates: featurePageStates(base().catalog || [], readiness.data || {}, base().bridge && base().bridge.featureExecutionFeatures) });
      }
    } catch (error) {
      // A guarded bridge is an expected state; do not manufacture data.
      if (!isCurrent()) return null;
      if (error && error.payload && error.payload.message) toast(error.payload.message, "error");
    }
  }

  async function payloadFor(fields, route) {
    const priorFlow = route && base().featureFlows && base().featureFlows[route];
    const priorInput = priorFlow && priorFlow.input && typeof priorFlow.input === "object" ? priorFlow.input : {};
    const values = { ...priorInput, ...fields };
    delete values.password;
    delete values.confirm_password;
    const replacingSource = replacingSingleImageSource(route, fields);
    const uploadIds = replacingSource ? [] : (Array.isArray(priorInput.upload_ids) ? priorInput.upload_ids.filter((item) => typeof item === "string" && item) : []);
    const priorUploads = replacingSource ? [] : (priorFlow && priorFlow.data && Array.isArray(priorFlow.data.uploads) ? priorFlow.data.uploads : []);
    for (const [field, value] of Object.entries(values)) {
      const files = typeof File !== "undefined" && value instanceof File
        ? [value]
        : (Array.isArray(value) && typeof File !== "undefined" && value.every((item) => item instanceof File) ? value : []);
      if (!files.length) continue;
      for (const file of files) {
        const existing = priorUploads.find((item) => item && item.id && item.file_name === file.name && Number(item.content_size || 0) === Number(file.size || 0));
        if (existing) {
          uploadIds.push(existing.id);
          continue;
        }
        const form = new FormData();
        form.append("file", file, file.name);
        // The Web App validates the bytes, then passes them only to bot-owned
        // staging. The browser never receives a local path or provider handle.
        const uploaded = await api("/uploads", {
          method: "POST",
          headers: { "Idempotency-Key": randomKey("upload") },
          body: form
        });
        const uploadId = uploaded && uploaded.data && uploaded.data.id;
        if (!uploadId) throw new Error("Core Bridge chưa xác nhận tệp đính kèm.");
        if (!uploadIds.includes(uploadId)) uploadIds.push(uploadId);
      }
      delete values[field];
    }
    if (uploadIds.length) values.upload_ids = uploadIds;
    return values;
  }

  async function refreshTelegramLoginChallenge({ silent = false } = {}) {
    let status;
    try {
      status = await api("/auth/telegram/login/status");
    } catch (error) {
      const failure = error && error.payload && typeof error.payload === "object" ? error.payload : {};
      const errorCode = String(failure.error_code || "");
      // These are expected terminal states for a one-time browser-bound
      // challenge. Preserve the public server message and stop polling rather
      // than turning an expired/rejected Bot proof into a noisy retry loop.
      if (["TELEGRAM_LOGIN_ACCOUNT_REQUIRED", "TELEGRAM_LOGIN_EXPIRED", "TELEGRAM_LOGIN_CHALLENGE_REQUIRED"].includes(errorCode)) {
        const terminalData = {
          ...(failure.data || {}),
          recovered: errorCode !== "TELEGRAM_LOGIN_CHALLENGE_REQUIRED",
          expired: errorCode === "TELEGRAM_LOGIN_EXPIRED"
        };
        // Do not retain an expired code/deep link in JavaScript state. A stale
        // one-time capability must never look usable after the server has
        // revoked it.
        merge({ telegramLoginFlow: { status: failure.status || "guarded", message: failure.message || "Telegram chưa liên kết với tài khoản Web.", errorCode, data: terminalData } });
        stopTelegramLoginPolling();
        if (!silent) toast(failure.message || "Telegram chưa liên kết với tài khoản Web.");
        return false;
      }
      throw error;
    }
    const previous = base().telegramLoginFlow && typeof base().telegramLoginFlow === "object" ? base().telegramLoginFlow : {};
    merge({ telegramLoginFlow: { ...previous, status: status.status || "awaiting_confirm", message: status.message, errorCode: status.error_code || "", data: { ...(previous.data || {}), ...(status.data || {}) } } });
    if (!(status.data && status.data.ready === true)) {
      if (!silent) toast(status.message);
      return false;
    }
    return completeTelegramLoginChallenge();
  }

  async function completeTelegramLoginChallenge() {
    // `complete` consumes only the browser-bound one-time challenge that this
    // page created. The Bot callback remains the identity proof; nothing in
    // this browser request contains a Telegram ID or Bot credential.
    stopTelegramLoginPolling();
    const completed = await api("/auth/telegram/login/complete", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
    toast(completed.message);
    await hydrate();
    const requested = requestedPortalRoute();
    // A successful Web sign-in owns a full Web Workspace even when the
    // customer has not opted into Telegram. Linking remains an optional
    // companion connector and must never trap an email/OAuth user in
    // onboarding before they can open their own projects or studios.
    window.location.assign(requested || "/dashboard");
    return true;
  }

  async function resumeTelegramLoginChallenge() {
    // On reload, the code is purposefully absent from JavaScript memory, but
    // the short-lived HttpOnly browser challenge remains a safe capability to
    // ask whether the Bot callback has already completed.
    if (!loginChallengeRoute() || telegramLoginResumeProbeInFlight || telegramChallengePending(base().telegramLoginFlow)) return false;
    telegramLoginResumeProbeInFlight = true;
    try {
      const status = await api("/auth/telegram/login/status");
      const previous = base().telegramLoginFlow && typeof base().telegramLoginFlow === "object" ? base().telegramLoginFlow : {};
      merge({ telegramLoginFlow: { ...previous, status: status.status || "awaiting_confirm", message: status.message, errorCode: status.error_code || "", data: { ...(status.data || {}), recovered: true } } });
      if (status.data && status.data.ready === true) return completeTelegramLoginChallenge();
      scheduleTelegramLoginPolling();
      return false;
    } catch (error) {
      const failure = error && error.payload && typeof error.payload === "object" ? error.payload : {};
      const errorCode = String(failure.error_code || "");
      // A normal visitor has no login challenge; do not render an error. An
      // expiry is useful feedback because the user may have returned from the
      // Bot after the one-time window elapsed.
      if (errorCode === "TELEGRAM_LOGIN_CHALLENGE_REQUIRED") return false;
      if (errorCode === "TELEGRAM_LOGIN_EXPIRED") {
        merge({ telegramLoginFlow: { status: failure.status || "failed", message: failure.message || "Mã đăng nhập Telegram đã hết hạn. Hãy tạo mã mới.", errorCode, data: { recovered: true, expired: true } } });
        stopTelegramLoginPolling();
      }
      return false;
    } finally {
      telegramLoginResumeProbeInFlight = false;
    }
  }

  async function completeTelegramLinkChallenge() {
    stopTelegramLinkPolling();
    const completed = await api("/auth/telegram/link/complete", { method: "POST", headers: { "Content-Type": "application/json" }, body: "{}" });
    merge({ linkStatus: completed.data || { linked: true }, linkFlow: {} });
    toast(completed.message);
    await hydrate();
    const requested = requestedPortalRoute();
    toast(requested ? "Telegram đã được liên kết. Đang mở lại workflow bạn đã chọn." : "Telegram đã được liên kết. Đang mở Dashboard.");
    window.location.assign(requested || "/dashboard");
    return true;
  }

  function recoverTelegramLinkFlow(result) {
    const data = result && result.data && typeof result.data === "object" ? result.data : {};
    const previous = base().linkFlow && typeof base().linkFlow === "object" ? base().linkFlow : {};
    const previousData = previous.data && typeof previous.data === "object" ? previous.data : {};
    if (data.pending !== true && data.ready_to_complete !== true) return false;
    merge({
      linkStatus: data,
      linkFlow: {
        ...previous,
        status: result.status || "awaiting_confirm",
        message: result.message || "Đang chờ Bot xác minh Telegram.",
        errorCode: result.error_code || "",
        // A reload never restores the code. If it only existed in memory,
        // expose a safe recovered marker and let the user either wait for the
        // Bot callback or deliberately replace the pending code.
        data: { ...previousData, ...data, recovered: typeof previousData.code !== "string" || !previousData.code }
      }
    });
    return true;
  }

  async function refreshTelegramLinkChallenge({ silent = false } = {}) {
    const result = await api("/auth/telegram/link/status");
    merge({ linkStatus: result.data || {} });
    if (result.data && result.data.linked) {
      stopTelegramLinkPolling();
      await hydrate();
      const requested = requestedPortalRoute();
      toast(requested ? "Telegram đã được liên kết. Đang mở lại workflow bạn đã chọn." : "Telegram đã được liên kết. Đang mở Dashboard.");
      window.location.assign(requested || "/dashboard");
      return true;
    }
    if (result.data && result.data.ready_to_complete === true) {
      recoverTelegramLinkFlow(result);
      return completeTelegramLinkChallenge();
    }
    if (recoverTelegramLinkFlow(result)) {
      if (!silent) toast(result.message);
      return false;
    }
    const previous = base().linkFlow && typeof base().linkFlow === "object" ? base().linkFlow : {};
    const previousData = previous.data && typeof previous.data === "object" ? previous.data : {};
    if (typeof previousData.code === "string" || previousData.recovered === true) {
      merge({ linkFlow: { status: "failed", message: "Mã liên kết Telegram đã hết hạn hoặc không còn thuộc phiên Web này. Hãy tạo mã mới.", errorCode: "LINK_CODE_INVALID", data: { expired: true } } });
      stopTelegramLinkPolling();
    }
    if (!silent) toast(result.message);
    return false;
  }

  async function resumeTelegramLinkChallenge(statusResult) {
    // A reload deliberately does not restore the code/deep link. The signed
    // session can nevertheless ask the server whether that *same* browser
    // session still owns an active pending challenge.
    if (!linkChallengeRoute() || telegramLinkResumeProbeInFlight || telegramChallengePending(base().linkFlow)) return false;
    telegramLinkResumeProbeInFlight = true;
    try {
      const result = statusResult || await api("/auth/telegram/link/status");
      if (!result || !(result.data && typeof result.data === "object")) return false;
      if (result.data.linked === true) return true;
      if (result.data.ready_to_complete === true) {
        recoverTelegramLinkFlow(result);
        return completeTelegramLinkChallenge();
      }
      if (recoverTelegramLinkFlow(result)) {
        scheduleTelegramLinkPolling();
      }
      return false;
    } finally {
      telegramLinkResumeProbeInFlight = false;
    }
  }

  function scheduleTelegramLoginPolling(delayMs) {
    const flow = base().telegramLoginFlow;
    if (!loginChallengeRoute() || !portalIsVisible() || !telegramChallengePending(flow)) return;
    telegramLoginPollDeadline = telegramChallengeDeadline(flow, telegramLoginPollDeadline);
    if (Date.now() >= telegramLoginPollDeadline || telegramLoginPollTimer) return;
    const delay = Number.isFinite(Number(delayMs)) ? Math.max(0, Number(delayMs)) : TELEGRAM_CHALLENGE_POLL_INTERVAL_MS;
    telegramLoginPollTimer = window.setTimeout(async () => {
      telegramLoginPollTimer = 0;
      try {
        const completed = await refreshTelegramLoginChallenge({ silent: true });
        telegramLoginPollFailures = 0;
        if (!completed) scheduleTelegramLoginPolling();
      } catch (_) {
        telegramLoginPollFailures += 1;
        const retryDelay = Math.min(TELEGRAM_CHALLENGE_POLL_MAX_BACKOFF_MS, TELEGRAM_CHALLENGE_POLL_INTERVAL_MS * (2 ** Math.min(telegramLoginPollFailures, 2)));
        scheduleTelegramLoginPolling(retryDelay);
      }
    }, delay);
  }

  function scheduleTelegramLinkPolling(delayMs) {
    const flow = base().linkFlow;
    if (!linkChallengeRoute() || !portalIsVisible() || !telegramChallengePending(flow)) return;
    telegramLinkPollDeadline = telegramChallengeDeadline(flow, telegramLinkPollDeadline);
    if (Date.now() >= telegramLinkPollDeadline || telegramLinkPollTimer) return;
    const delay = Number.isFinite(Number(delayMs)) ? Math.max(0, Number(delayMs)) : TELEGRAM_CHALLENGE_POLL_INTERVAL_MS;
    telegramLinkPollTimer = window.setTimeout(async () => {
      telegramLinkPollTimer = 0;
      try {
        const completed = await refreshTelegramLinkChallenge({ silent: true });
        telegramLinkPollFailures = 0;
        if (!completed) scheduleTelegramLinkPolling();
      } catch (_) {
        telegramLinkPollFailures += 1;
        const retryDelay = Math.min(TELEGRAM_CHALLENGE_POLL_MAX_BACKOFF_MS, TELEGRAM_CHALLENGE_POLL_INTERVAL_MS * (2 ** Math.min(telegramLinkPollFailures, 2)));
        scheduleTelegramLinkPolling(retryDelay);
      }
    }, delay);
  }

  async function contentStudioMutation({ action, route, scope, path, method, payload, onSuccess }) {
    const submission = acquireSubmission(scope, JSON.stringify(payload));
    if (!submission) {
      toast("Thao tác Content Studio đang chờ máy chủ xác nhận.", "error");
      return null;
    }
    let acknowledged = false;
    setActionBusy(action, route, true);
    try {
      const result = await api(path, {
        method: method || "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...payload, idempotency_key: submission.key })
      });
      acknowledged = true;
      if (typeof onSuccess === "function") await onSuccess(result);
      return result;
    } catch (error) {
      acknowledged = Boolean(error && Number.isInteger(error.status) && error.status > 0);
      throw error;
    } finally {
      releaseSubmission(submission);
      if (acknowledged) discardSubmission(scope, submission);
      setActionBusy(action, route, false);
    }
  }

